#print(customer_schema)
#print(lineitem_schema)
lineitem = (spark.read.option("sep","|").
            option("header",False).
            schema(lineitem_schema).
            csv("data/tpch/lineitem.tbl"))

#print(order_schema)

orders= (spark.read.option("sep","|").
         option("header",False).
         schema(order_schema).csv("data/tpch/orders.tbl"))

print(orders.show(5))
"""

**Tasks**
- [ ] **TPC-H Q1 style:** group lineitem by `l_returnflag, l_linestatus`; compute sum of quantity, sum of revenue, avg price, avg discount, and a row count. Order by the two keys.
- [ ] Revenue per `order_year` / `order_month`.
- [ ] Top 10 customers by total order value (group orders by `o_custkey`).
- [ ] Count distinct order priorities and ship modes.
- [ ] One summary table combining 4+ aggregates, each aliased.

**Deliverable:** A notebook with at least 4 grouped summaries, each with a one-line interpretation.

"""


#lineitem.show(10)
#1
lineitem = lineitem.withColumn(
    "revenue",
    F.col("l_extendedprice") * (1 - F.col("l_discount"))
)

lineitem.groupBy(
    "l_returnflag",
    "l_linestatus"
).agg(
    F.sum("l_quantity").alias("sum_quantity"),
    F.sum("revenue").alias("sum_revenue"),
    F.avg("l_extendedprice").alias("avg_price"),
    F.avg("l_discount").alias("avg_discount"),
    F.count("*").alias("row_count")
).orderBy(
    "l_returnflag",
    "l_linestatus"
).show()


#2
orders = orders.withColumn("order_year", F.year("o_orderdate"))
orders = orders.withColumn("order_month", F.month("o_orderdate"))

# orders.groupBy("order_year", "order_month").agg(
#     F.sum("o_totalprice").alias("total_revenue")
# ).orderBy("order_year", "order_month").show()


#3

#orders.groupBy("o_custkey").agg(F.sum("o_totalprice").alias("total_price")).sort(F.col("total_price").desc()).show(10)

#4

#orders.agg(F.count_distinct("o_orderpriority").alias("order priority")).show()

orders.select("o_orderpriority").distinct().show()

#5


orders.groupBy("o_orderpriority").agg(F.sum("o_totalprice").alias("total_price"),
                                      F.avg("o_totalprice").alias("avg_totalprice"),
                                      F.stddev("o_totalprice").alias("std"),
                                      F.count_distinct("o_orderstatus").alias("distinct_orderstatus")).orderBy(F.col("o_orderpriority")).show()

